// Process backend response — output one item per chunk
const input = $('When Called').first().json;
const backendResponse = $input.first().json;

// Backend returns: { success, file_name, extracted_text, chunks, chunk_count, char_count }
const chunks = backendResponse.chunks || [];
const fileName = input.file_name || backendResponse.file_name || 'uploaded_file';
const userId = input.userID;
const category = input.category || 'documents';

if (!chunks.length) {
  // Fallback: use extracted_text as single chunk
  const extractedText = backendResponse.extracted_text || '';
  if (!extractedText.trim()) {
    throw new Error(`No text could be extracted from file: ${fileName}`);
  }
  return {
    json: {
      user_id: userId,
      category: category,
      document: `File: ${fileName}\n\n${extractedText}`,
      source: 'file_upload',
      file_name: fileName,
      chunk_index: 0,
      total_chunks: 1
    }
  };
}

// Return one item per chunk
return chunks.map((chunk, index) => ({
  json: {
    user_id: userId,
    category: category,
    document: `File: ${fileName} [Part ${index + 1}/${chunks.length}]\n\n${chunk}`,
    source: 'file_upload',
    file_name: fileName,
    chunk_index: index,
    total_chunks: chunks.length
  }
}));

// Collect all inserted chunk IDs and return final response
const allItems = $input.all();
const insertedIds = allItems.map(item => item.json?.id || null).filter(Boolean);

const input = $('When Called').first().json;
const fileName = input.file_name || 'uploaded_file';

return {
  json: {
    success: true,
    action: 'file_uploaded',
    user_id: input.userID,
    file_name: fileName,
    file_type: input.file_type || '',
    category: input.category || 'documents',
    chunks_inserted: insertedIds.length,
    inserted_ids: insertedIds,
    timestamp: new Date().toISOString()
  }
};
